window.addEventListener("load",()=>{const lenis=new Lenis();lenis.on("scroll",ScrollTrigger.update);gsap.ticker.add((time)=>{lenis.raf(time*1000)});gsap.ticker.lagSmoothing(0)});window.addEventListener("load",()=>{gsap.registerPlugin(ScrollTrigger,ScrollToPlugin);ScrollTrigger.create({trigger:"#bg-color-change-tigger",start:"top top",end:"bottom bottom",onEnter:()=>{document.getElementById("back").classList.add("bg-color-active");document.getElementById("tergeting-section").classList.add("bg-color-active")},onLeaveBack:()=>{document.getElementById("back").classList.remove("bg-color-active");document.getElementById("tergeting-section").classList.remove("bg-color-active")},});let mm=gsap.matchMedia();mm.add("(min-width: 768px)",()=>{const sectionName2="#tergeting-section";const blockSelector2=".timeline-content-item";const imageSelector2=".timeline-image";const imageClassName2=".timeline-content";const allBlocks=gsap.utils.toArray(blockSelector2);const blocks2=allBlocks.filter((block)=>block.textContent.trim()!=="");const images2=gsap.utils.toArray(imageSelector2);const blocksContainer2=document.querySelector(`${sectionName2} ${imageClassName2}`);const dots2=gsap.utils.toArray(".timeline-line .dot");gsap.set(blocks2,{opacity:0,y:0});gsap.set(blocks2[0],{opacity:1});gsap.set(images2,{opacity:0});gsap.set(images2[0],{opacity:1});ScrollTrigger.create({trigger:sectionName2,start:"top top",endTrigger:blocks2[blocks2.length-1],end:"bottom center",pin:!0,scrub:!0,invalidateOnRefresh:!0,markers:!1,});blocks2.forEach((block,index)=>{ScrollTrigger.create({trigger:block,start:"top center",end:"bottom center",scrub:!0,onEnter:()=>activate2(index),onEnterBack:()=>activate2(index),invalidateOnRefresh:!0,})});let mayHeight=100;blocks2.forEach((block,index)=>{gsap.to(block,{y:()=>`-${(blocks2.length - 1) * 100}%`,ease:"none",scrollTrigger:{trigger:blocksContainer2,start:"top 20%",endTrigger:blocks2[blocks2.length-1],end:"bottom 60%",scrub:2,invalidateOnRefresh:!0,},})});function activate2(index){blocks2.forEach((b,i)=>{gsap.to(b,{opacity:i===index?1:0,duration:0.3,overwrite:"auto",})});images2.forEach((img,i)=>{gsap.to(img,{opacity:i===index?1:0,duration:0.5,ease:"power1.inOut",overwrite:"auto",})});dots2.forEach((dot,i)=>{dot.classList.toggle("active",i===index);dot.classList.toggle("isFinished",i<index)});const progressLine=document.querySelector(".timeline-line-progress");if(progressLine){const totalDots=dots2.length;const percentage=(index/(totalDots-1))*100;progressLine.style.height=`${percentage}%`}}
dots2.forEach((dot,i)=>{dot.addEventListener("click",()=>{const test=document.querySelector(".timeline-content");const contentHeight=test.offsetHeight;gsap.to(window,{duration:0.2,scrollTo:{y:blocks2[i],offsetY:contentHeight*0.75,},ease:"none",})})})});mm.add("(max-width: 767px)",()=>{const contentItems=document.querySelectorAll(".timeline-content-item");const images=document.querySelectorAll(".timeline-image");const dots=document.querySelectorAll(".dot");let activeIndex=0;gsap.set(contentItems,{xPercent:100,opacity:0});gsap.set(images,{xPercent:100,opacity:0});gsap.set(contentItems[0],{xPercent:0,opacity:1});gsap.set(images[0],{xPercent:0,opacity:1});function goToSlide(index){if(index===activeIndex)return;let direction=index>activeIndex?1:-1;let tl=gsap.timeline();tl.to([contentItems[activeIndex],images[activeIndex]],{xPercent:-100*direction,opacity:0,duration:0.4,ease:"power2.inOut",}).set([contentItems[index],images[index]],{xPercent:100*direction,opacity:0,}).to([contentItems[index],images[index]],{xPercent:0,opacity:1,duration:0.4,ease:"power2.inOut",});updateDots(index);activeIndex=index}
dots.forEach((dot,i)=>{dot.addEventListener("click",()=>{goToSlide(i)})});function updateDots(index){dots.forEach((dot,i)=>{dot.classList.toggle("active",i===index);dot.classList.toggle("isFinished",i<index)});const progressLine=document.querySelector(".timeline-line-progress");if(progressLine){const totalDots=dots.length;const percentage=(index/(totalDots-1))*100;progressLine.style.width=`${percentage}%`}}});const verticalCards=gsap.utils.toArray(".panel__card");verticalCards.forEach((verticalCard,index)=>{if(index!==0){gsap.set(verticalCard,{yPercent:135,})}});const mainTimeline=gsap.timeline({scrollTrigger:{trigger:".optimization-container",pin:!0,start:"top 4%",end:()=>`+=${verticalCards.length * 100}%`,scrub:1,pinSpacing:!0,invalidateOnRefresh:!0,},defaults:{ease:"none",},});verticalCards.forEach((verticalCard,index)=>{if(index===0)return;mainTimeline.to(verticalCard,{yPercent:0,duration:1,});mainTimeline.fromTo(verticalCard,{scale:1.05,},{scale:1,duration:0.5,},">-0.7",)});const horizontalCardContainer=document.querySelector(".horizontal");const horizontalCards=gsap.utils.toArray(".case-study-container");const stickyWrapper=document.querySelector(".sticky-body");function getScrollAmount(){let extraWidth=window.innerWidth-horizontalCardContainer.offsetWidth;return-(horizontalCardContainer.scrollWidth-window.innerWidth+extraWidth)}
const horizontalTimeline=gsap.timeline({scrollTrigger:{trigger:".sticky-body",start:"top 3%",end:()=>`+=${horizontalCardContainer.scrollWidth / 2}`,scrub:0.1,pin:!0,invalidateOnRefresh:!0,anticipatePin:1,},});horizontalTimeline.to(horizontalCardContainer,{x:getScrollAmount,ease:"none",});horizontalCards.forEach((horizontalCard)=>{gsap.from(horizontalCard,{scrollTrigger:{trigger:horizontalCard,containerAnimation:horizontalTimeline,start:"left 85%",end:"center 60%",scrub:!0,invalidateOnRefresh:!0,},},"<",)});function syncImageChangeAnimation({sectionName,blockSelector,imageSelector,imageClassName,spacial=!1}){const blocks=gsap.utils.toArray(blockSelector);const images=gsap.utils.toArray(imageSelector);const blocksContainer=document.querySelector(`${sectionName} ${imageClassName}`);ScrollTrigger.matchMedia({"(min-width: 850px)":function(){ScrollTrigger.create({trigger:sectionName,start:"top 14%",endTrigger:blocks[blocks.length-1],end:"bottom center",pin:!0,scrub:!0,invalidateOnRefresh:!0,});blocks.forEach((block,index)=>{if(index===blocks.length-1)return;ScrollTrigger.create({trigger:block,start:"top center",end:"bottom center",scrub:!0,onEnter:()=>activate(index),onEnterBack:()=>activate(index),invalidateOnRefresh:!0,})});let mayHeight=spacial?90:105;blocks.forEach((block,index)=>{gsap.to(block,{y:()=>`-${blocks.length * mayHeight}% + ${index * 100}%`,ease:"none",scrollTrigger:{trigger:blocksContainer,start:"top 20%",endTrigger:blocks[blocks.length-1],end:"bottom 65%",scrub:3,invalidateOnRefresh:!0,},})});function activate(index){blocks.forEach((b,i)=>{gsap.to(b,{opacity:i===index?1:0.3,duration:0.3,})});images.forEach((img,i)=>{gsap.to(img,{opacity:i===index?1:0,duration:0.5,ease:"power1.inOut",overwrite:"auto",})})}},})}
syncImageChangeAnimation({sectionName:".amazon-ppc-section",blockSelector:".amazon-ppc-content-text",imageSelector:".amazon-ppc-img img",imageClassName:".amazon-content-img",});syncImageChangeAnimation({sectionName:".amazon-keyword2-section",blockSelector:".amazon-keyword2-content-text",imageSelector:".amazon-keyword2-img img",imageClassName:".amazon-content-img",spacial:!0,});["#bg-color-change-tigger2","#bg-color-change-tigger3","#bg-color-change-tigger4"].forEach((id,i)=>{ScrollTrigger.create({trigger:id,start:"top top",end:"bottom bottom",onEnter:()=>{document.getElementById("main-section").classList.toggle("bg-color-active",i%2===0)},onLeaveBack:()=>{document.getElementById("main-section").classList.toggle("bg-color-active",i%2!==0)},})});function updateLayout(){ScrollTrigger.refresh()}
window.addEventListener("load",updateLayout);window.addEventListener("resize",updateLayout)})